Construct a graph and just do DFS. Graph construction took 95% of the (coding) time. 
```
using namespace std;

vector<vector<string>> grid = {{"/", "\\", "\\"},
                               {"\\", "/", "\\"},
                               {"\\", "\\", "/"}};

using Graph = unordered_map<int, unordered_set<int>>;

Graph buildGraph(const vector<vector<string>> &grid)
{
    int numPointsOnOneRow = grid[0].size() + 1;
    int totalPoints = grid.size() * numPointsOnOneRow;

    int maxRow = grid.size() - 1;
    int maxCol = grid[0].size() - 1;

    Graph g;
    for (int row = 0; row < grid.size(); row++)
    {
        // Connect to lower point along the left border
        int topLeftPointId = row * numPointsOnOneRow + 1;
        int bottomLeftPointId = topLeftPointId + numPointsOnOneRow;
        g[topLeftPointId].insert(bottomLeftPointId);
        g[bottomLeftPointId].insert(topLeftPointId);

        // Connect along right border
        int topRightPointId = (row + 1) * numPointsOnOneRow;
        int bottomRightPointId = topRightPointId + numPointsOnOneRow;
        g[topRightPointId].insert(bottomRightPointId);
        g[bottomRightPointId].insert(topRightPointId);

        for (int col = 0; col < grid[0].size(); col++)
        {
            if (row == 0)
            {
                // Connect along top border
                g[col + 1].insert(col + 2);
                g[col + 2].insert(col + 1);
            }
            if (row == maxRow)
            {
                // Connect along bottom border
                int startingPoint = ((maxRow + 1) * numPointsOnOneRow) + 1;
                g[startingPoint + col].insert(startingPoint + col + 1);
                g[startingPoint + col + 1].insert(startingPoint + col);
            }
            if (grid[row][col].compare("\\") == 0)
            {
                // Connect left top to right bottom
                int leftTop = (row * numPointsOnOneRow) + col + 1;
                int bottomRight = leftTop + numPointsOnOneRow + 1;
                g[leftTop].insert(bottomRight);
                g[bottomRight].insert(leftTop);
            }
            if (grid[row][col].compare("/") == 0)
            {
                // Connect right top to left bottom
                int rightTop = (row * numPointsOnOneRow) + col + 2;
                int leftBottom = rightTop + numPointsOnOneRow - 1;
                g[rightTop].insert(leftBottom);
                g[leftBottom].insert(rightTop);
            }
        }
    }

    return g;
}

void traverse(int source, int destination, vector<int> &path, Graph &g, unordered_set<int> &visited)
{
    if (source == destination)
    {
        for (int node : path)
        {
            cout << node << ", ";
        }
        cout << destination << endl;
        return;
    }
    if (visited.find(source) != visited.end())
        return;
    visited.insert(source);
    path.push_back(source);
    for (int neighbor : g[source])
    {
        traverse(neighbor, destination, path, g, visited);
    }
    visited.erase(source);
    path.pop_back();
    return;
}

int main()
{
    auto graph = buildGraph(grid);
    vector<int> path;
    unordered_set<int> visited;
    traverse(1, 16, path, graph, visited);
}
```

