public class ConstructGraphWithSlashes {
    static int[][] dirs = new int[][] {{0, 1}, {0, - 1}, {1, 0}, {- 1, 0}};

    static public int constructGraph(char[][] grid) {
        int n = grid.length;
        String[][] newGrid = new String[(n*2)+(n+1)][(n * 2) + (n + 1)];
        int newLen = newGrid.length;
        for (int i = 0; i < newLen; i++) {
            Arrays.fill(newGrid[i], " ");
        }

        for (int j = 0; j < newLen; j++) {
            newGrid[0][j] = "-";
            newGrid[newLen-1][j] = "-";
        }

        for(int i = 1; i<newLen-1; i++) {
            newGrid[i][0] = "|";
            newGrid[i][newLen - 1] = "|";
        }

        int num = 1;

        for(int i = 0; i<newLen; i+=3) {
            for(int j = 0; j<newLen; j+=3) {
                newGrid[i][j] = String.valueOf(num);
                num++;
            }
        }

        int ii=0, jj = 0;
        for(int i = 0; i<n; i++) {
            for(int j = 0; j<n; j++) {
                ii = (i) * 2 + 1 + i;
                jj = (j) * 2 + 1 + j;
                if(grid[i][j] == '\\') {
                    newGrid[ii][jj] = newGrid[ii + 1][jj + 1] = "0";
                } else if(grid[i][j] == '/') {
                    newGrid[ii][jj + 1] = newGrid[ii + 1][jj] = "0";
                }
            }
        }

        for(int i = 0; i<newLen; i++) {
            for(int j = 0; j<newLen; j++) {
                System.out.print(newGrid[i][j] + " ");
            }
            System.out.println();
        }
        return 0;
    }

    static private void dfs(int[][] grid, int r, int c, int gr, int gc) {
        if(r >= 0 && r<gr && c >= 0 && c<gc && grid[r][c] == 0) {
            grid[r][c] = 1;
            for(int[] d: dirs) {
                int nr = r + d[0];
                int nc = c + d[1];
                dfs(grid, nr, nc, gr, gc);
            }
        }
    }

    public static void main(String[] args) {
        char[][] slashes = {{'/', '\\', ' '},
                            {' ', '/', ' '},
                            {' ', ' ', '/'}};

        constructGraph(slashes);

    }
}

My python solution.  This took about an hour of debugging my off-by-ones.  In an interview I'd fill out the `get_connected_nodes` function last.

You could also pre-build the graph and traverse it.  That probably would've been cleaner.  The backtracking dominates the time and space complexity here, so I don't think either solution is better than the other.

```python
def find_paths():
    slashes = [["/", " ", " "],
               [" ", "/", " "],
               [" ", " ", "/"]]

    result = []
    target = (len(slashes)+1)**2

    def traverse(cur_path, node, visited):
        if node == target:
            result.append(list(cur_path))

        for conn in get_connected_nodes(node):
            if conn not in visited:
                cur_path.append(conn)
                visited.add(conn)
                traverse(cur_path, conn, visited)
                cur_path.pop()
                visited.remove(conn)

    def get_connected_nodes(node):
        result = []
        node_row = (node-1) // (len(slashes)+1)
        node_col = (node-1) % (len(slashes) + 1)
        top_left_slash = (
            None
            if node_row == 0 or node_col == 0
            else slashes[node_row - 1][node_col - 1]
        )
        top_right_slash = (
            None
            if node_row == 0 or node_col == len(slashes)
            else slashes[node_row-1][node_col]
        )
        bottom_left_slash = (
            None
            if node_row == len(slashes) or node_col == 0
            else slashes[node_row][node_col-1]
        )
        bottom_right_slash = (
            None
            if node_row == len(slashes) or node_col == len(slashes)
            else slashes[node_row][node_col]
        )

        if top_left_slash == "\\":
            result.append(node-len(slashes)-2)
        if top_right_slash == "/":
            result.append(node-len(slashes))
        if bottom_left_slash == "/":
            result.append(node+len(slashes))
        if bottom_right_slash == "\\":
            result.append(node+len(slashes)+2)
        if node_row == 0 or node_row == len(slashes):
            if node_col < len(slashes):
                result.append(node+1)
            if node_col > 0:
                result.append(node-1)
        if node_col == 0 or node_col == len(slashes):
            if node_row > 0:
                result.append(node - len(slashes) - 1)
            if node_row < len(slashes):
                result.append(node + len(slashes) + 1)
        return result

    traverse([1], 1, set())
    return result
